Example Code:

#include    <ctype.h>
#include    <errno.h>
#include    <limits.h>
#include    <stdarg.h>
#include    <stdio.h>
#include    <stdlib.h>
#include    <string.h>
#include    <sys/wait.h>
#include    <signal.h>
#include    <time.h>
#include    <unistd.h>
#include    <pthread.h>


#define T_TIMEOUT   60

static int  T_timeout;
static int  T_int;

static void t_sighandler();

static void
t_sighandler(int sig) {
    T_int = sig;
}

int
main(int argc, char **argv)
{

    pid_t           child;
    pid_t           deadpid;
    int         status;
    struct sigaction    sa;

    T_timeout = T_TIMEOUT;

    /* setup signals */

    sa.sa_flags = 0;
    sigfillset(&sa.sa_mask);
    sa.sa_handler = t_sighandler;
    (void) sigaction(SIGALRM, &sa, NULL);
    (void) sigaction(SIGINT,  &sa, NULL);

    setbuf(stdout, NULL);

    child = fork();
    if (child == 0) {
        sleep(10);
        exit(0);
    }
    else if (child > 0) {

        T_int = 0;
        sa.sa_handler = t_sighandler;
        (void) sigaction(SIGALRM, &sa, NULL);
        alarm(T_timeout);

        deadpid = (pid_t) -1;
        while (deadpid != child) {
            deadpid = waitpid(child, &status, 0);
	printf("child %d, deadpid %d, errno %d, T_int %d\n", 
		child, deadpid, errno, T_int);
            if (deadpid == child) {
                printf("deadpid == child\n");
                if (WIFSIGNALED(status)) {
                    if (WTERMSIG(status) == SIGTERM)
                        printf("the test case timed out\n");
                    else
                        printf("the test case caused exception %d\n",
				WTERMSIG(status));
                }
            }
            else if ((deadpid == -1) && (errno == EINTR) && T_int) {
                printf("terminating child\n");
                kill(child, SIGTERM);
                T_int = 0;
            }
            else if ((deadpid == -1) &&
                 ((errno == ECHILD) || (errno == ESRCH))) {
                printf("no such process\n");
                break;
            }
        }

        sa.sa_handler = SIG_IGN;
        (void) sigaction(SIGALRM, &sa, NULL);
        alarm(0);
    }
    else {
        printf("fork failed, errno == %d\n", errno);
    }

    return(0);
}
